-- Consolidated initial schema for Blixa (ColDP editor).
--
-- Squashed on 2026-07-21 from the original incremental migrations V1..V34: the deploy
-- database was wiped, so the migration history was collapsed into this single baseline.
-- Generated by pg_dump --schema-only of the fully-migrated schema (pg_dump preamble,
-- psql meta-commands, and ownership COMMENTs stripped so Flyway/JDBC runs it cleanly).


CREATE EXTENSION IF NOT EXISTS pg_trgm WITH SCHEMA public;

CREATE TABLE public.app_user (
    id bigint NOT NULL,
    orcid text,
    username text NOT NULL,
    email text,
    display_name text,
    given text,
    family text,
    password_hash text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    admin boolean DEFAULT false NOT NULL,
    state text DEFAULT 'ACTIVE'::text NOT NULL
);

ALTER TABLE public.app_user ALTER COLUMN id ADD GENERATED ALWAYS AS IDENTITY (
    SEQUENCE NAME public.app_user_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1
);

CREATE TABLE public.author (
