CREATE INDEX change_entity_idx ON public.change USING btree (project_id, entity_type, entity_id, at DESC);

CREATE INDEX change_project_at_idx ON public.change USING btree (project_id, at DESC, id DESC);

CREATE INDEX change_task_idx ON public.change USING btree (project_id, task_id);

CREATE UNIQUE INDEX col_match_run_active_idx ON public.col_match_run USING btree (project_id) WHERE (status = 'RUNNING'::text);

CREATE INDEX col_match_run_project_idx ON public.col_match_run USING btree (project_id, started_at DESC);

CREATE INDEX discussion_change_by_change_idx ON public.discussion_change USING btree (change_id);

CREATE INDEX discussion_comment_thread_idx ON public.discussion_comment USING btree (project_id, discussion_id, id);

CREATE INDEX discussion_follow_by_discussion_idx ON public.discussion_follow USING btree (project_id, discussion_id);

CREATE INDEX discussion_fts ON public.discussion USING gin (to_tsvector('simple'::regconfig, ((COALESCE(title, ''::text) || ' '::text) || COALESCE(body, ''::text))));

CREATE INDEX discussion_project_author_idx ON public.discussion USING btree (project_id, author_id);

CREATE INDEX discussion_project_status_idx ON public.discussion USING btree (project_id, status);

CREATE INDEX discussion_usage_by_usage_idx ON public.discussion_usage USING btree (project_id, usage_id);

CREATE INDEX distribution_usage_idx ON public.distribution USING btree (project_id, usage_id);

CREATE INDEX estimate_usage_idx ON public.estimate USING btree (project_id, usage_id);

CREATE UNIQUE INDEX export_run_active_idx ON public.export_run USING btree (project_id) WHERE (status = 'RUNNING'::text);

CREATE INDEX export_run_project_idx ON public.export_run USING btree (project_id, started_at DESC);

CREATE INDEX import_run_user_idx ON public.import_run USING btree (user_id, started_at DESC);

CREATE INDEX issue_entity_idx ON public.issue USING btree (project_id, entity_type, entity_id);

CREATE INDEX issue_project_status_idx ON public.issue USING btree (project_id, status, severity);

CREATE INDEX join_request_project_idx ON public.join_request USING btree (project_id);

CREATE INDEX lock_project_idx ON public.lock USING btree (project_id);

CREATE INDEX media_usage_idx ON public.media USING btree (project_id, usage_id);

CREATE UNIQUE INDEX merge_run_active_idx ON public.merge_run USING btree (target_project_id) WHERE (status = ANY (ARRAY['RUNNING'::text, 'APPLYING'::text]));

CREATE INDEX merge_run_target_idx ON public.merge_run USING btree (target_project_id, started_at DESC);

CREATE INDEX name_relation_usage_idx ON public.name_relation USING btree (project_id, usage_id);

CREATE INDEX name_usage_parent_idx ON public.name_usage USING btree (project_id, parent_id);

CREATE INDEX name_usage_sciname_trgm ON public.name_usage USING gin (scientific_name public.gin_trgm_ops);

CREATE INDEX project_member_user_idx ON public.project_member USING btree (user_id);

CREATE INDEX property_usage_idx ON public.property USING btree (project_id, usage_id);

CREATE INDEX reference_citation_fts ON public.reference USING gin (to_tsvector('simple'::regconfig, COALESCE(citation, ''::text)));

CREATE INDEX reference_citation_trgm ON public.reference USING gin (citation public.gin_trgm_ops);

CREATE INDEX release_project_idx ON public.release USING btree (project_id, created_at DESC, id DESC);

CREATE INDEX synonym_accepted_accepted_idx ON public.synonym_accepted USING btree (project_id, accepted_id);

CREATE INDEX task_project_idx ON public.task USING btree (project_id, status);

CREATE INDEX type_material_usage_idx ON public.type_material USING btree (project_id, usage_id);

CREATE INDEX vernacular_usage_idx ON public.vernacular USING btree (project_id, usage_id);

